// Build the list of 8 brain dump file configs
const BUCKET = 'obsidian-vault';
const PREFIX = 'Homelab';

const domains = [
  { domain: 'Faith',     area: 'faith',     emoji: '🙏', rock: 'Launch the Social Media Bible Study',      file: 'BrainDump — Faith.md' },
  { domain: 'Family',    area: 'family',    emoji: '💒', rock: 'Marriage Alignment with Christy',           file: 'BrainDump — Family.md' },
  { domain: 'Business',  area: 'business',  emoji: '🚀', rock: 'Ship the MVP — Echelon Seven',              file: 'BrainDump — Business (Echelon Seven).md' },
  { domain: 'Consulting',area: 'consulting',emoji: '💼', rock: null,                                        file: 'BrainDump — Consulting.md' },
  { domain: 'Work',      area: 'work',      emoji: '🏥', rock: 'Deliver Union Project + Position for Exit', file: 'BrainDump — Work (Parallon).md' },
  { domain: 'Health',    area: 'health',    emoji: '💪', rock: 'Hip Decision + 3x/week Gym for 8 Weeks',   file: 'BrainDump — Health.md' },
  { domain: 'Home',      area: 'home',      emoji: '🏠', rock: null,                                        file: 'BrainDump — Home.md' },
  { domain: 'Personal',  area: 'personal',  emoji: '🤖', rock: null,                                        file: 'BrainDump — Personal.md' }
];

return domains.map(d => ({
  json: {
    ...d,
    bucket: BUCKET,
    fileKey: `${PREFIX}/00_Inbox/brain-dumps/${d.file}`,
    masterTaskListKey: `${PREFIX}/10_Active Projects/Active Personal/!!! MASTER TASK LIST.md`
  }
}));

// Extract text content from the S3 binary download, merge with metadata from loop
const loopItem = $('Loop: Read Each File').item.json;
const binaryKey = Object.keys($input.item.binary || {})[0] || 'data';
const binaryData = $input.item.binary?.[binaryKey];

let fileContent = '';
if (binaryData?.data) {
  fileContent = Buffer.from(binaryData.data, 'base64').toString('utf-8');
}

// Check if download failed (no content = file probably doesn't exist yet)
const hasContent = fileContent.trim().length > 10;

return [{
  json: {
    ...loopItem,
    rawContent: fileContent,
    downloadSuccess: hasContent
  }
}];

// Collect items across loop iterations using staticData.
// Guard: if collected has stale data from a prior failed run, check timestamp.
const item = $input.item.json;
const state = $workflow.staticData;

// Initialize or reset stale data (>2h old = stale from a failed prior run)
const now = Date.now();
if (!state.collected || !state.collectedAt || (now - state.collectedAt) > 7200000) {
  state.collected = [];
}
state.collectedAt = now;

if (item.downloadSuccess !== false) {
  state.collected.push(item);
}

return [{ json: item }];

// ═══════════════════════════════════════════════════════════
// PARSE & ANALYZE — the brain of the workflow
// Reads all accumulated brain dump content from static data,
// classifies tasks vs review items, builds output schema.
// ═══════════════════════════════════════════════════════════

const state = $workflow.staticData;
const files = state.collected || [];

// Clear for next run
state.collected = [];

const today = new Date().toISOString().split('T')[0];

const MASTER_TASK_LIST_KEY = 'Homelab/10_Active Projects/Active Personal/!!! MASTER TASK LIST.md';

// Section heading keywords (case-insensitive)
const SECTION_KEYWORDS = {
  needleMovers:  /needle\s*movers?|🎯/i,
  todos:         /to\s*do|tasks?|action/i,
  notes:         /notes?|quick\s*notes?/i,
  articles:      /articles?|resources?|links?|reading/i,
  ideas:         /ideas?|possibilities/i,
  organize:      /organize|to\s*organize|things\s*to\s*organize/i,
  recurring:     /recurring|rhythms?|habits?/i
};

function parseContent(text) {
  if (!text || text.trim().length < 5) return null;
  const sections = { needleMovers: [], todos: [], notes: [], articles: [], ideas: [], organize: [], recurring: [] };
  let currentSection = null;

  for (const line of text.split('\n')) {
    const trimmed = line.trim();
    if (trimmed.startsWith('#')) {
      currentSection = null;
      for (const [key, rx] of Object.entries(SECTION_KEYWORDS)) {
        if (rx.test(trimmed)) { currentSection = key; break; }
      }
      continue;
    }
    if (currentSection && trimmed && !trimmed.match(/^<!--|^---$|^\*Only/)) {
      const cleanLine = trimmed.replace(/^-\s*/, '').trim();
      if (cleanLine.length > 2) sections[currentSection].push(cleanLine);
    }
  }
  const hasAny = Object.values(sections).some(arr => arr.length > 0);
  return hasAny ? sections : null;
}

function buildTaskLine(text, area, priority, due, rock) {
  let line = `- [ ] ${text} [area:: ${area}] [priority:: ${priority}]`;
  if (due) line += ` [due:: ${due}]`;
  return line;
}

function extractDue(text) {
  const m = text.match(/\[due::\s*(\d{4}-\d{2}-\d{2})\s*\]/);
  return m ? m[1] : null;
}

function cleanTaskText(text) {
  return text
    .replace(/\[area::[^\]]+\]/g, '')
    .replace(/\[priority::[^\]]+\]/g, '')
    .replace(/\[due::[^\]]+\]/g, '')
    .trim();
}

const priorityATasks = [];
const priorityBTasks = [];
const reviewItems = { notes: [], articles: [], ideas: [], organize: [], recurring: [] };
const clearedDumps = [];
const processedDomains = [];

for (const file of files) {
  const sections = parseContent(file.rawContent);
  if (!sections) continue;

  processedDomains.push({ domain: file.domain, area: file.area, emoji: file.emoji });

  // Needle Movers → Priority A with rock
  for (const item of sections.needleMovers) {
    const due = extractDue(item);
    const text = cleanTaskText(item);
    const line = buildTaskLine(text, file.area, 'A', due, file.rock);
    priorityATasks.push({ domain: file.domain, area: file.area, emoji: file.emoji, raw: text, due, rock: file.rock, line });
  }

  // To-Do items → respect inline priority, default B
  for (const item of sections.todos) {
    const pMatch = item.match(/\[priority::\s*([A-C])\s*\]/i);
    const priority = pMatch ? pMatch[1].toUpperCase() : 'B';
    const due = extractDue(item);
    const text = cleanTaskText(item);
    const line = buildTaskLine(text, file.area, priority, due, priority === 'A' ? file.rock : null);
    const task = { domain: file.domain, area: file.area, emoji: file.emoji, raw: text, due, priority, rock: priority === 'A' ? file.rock : null, line };
    if (priority === 'A') priorityATasks.push(task);
    else priorityBTasks.push(task);
  }

  // Review items (email only, never auto-filed)
  for (const key of ['notes', 'articles', 'ideas', 'organize', 'recurring']) {
    for (const item of sections[key]) {
      reviewItems[key].push({ domain: file.domain, area: file.area, text: item });
    }
  }

  // Build cleared template for this domain
  const clearedContent = `---
domain: ${file.domain}
status: empty
last_processed: ${today}
---

## 🎯 Needle Movers
<!-- Tasks that directly advance your Q2 quarterly rock for ${file.domain} -->


## ✅ To-Do's
<!-- Actionable tasks. Add [priority:: A/B/C] and [due:: YYYY-MM-DD] -->


## 📝 Quick Notes
<!-- Non-actionable observations, thoughts, reference material -->


## 📚 Articles & Resources
<!-- Links and resources to review -->


## 🗂️ Things to Organize
<!-- Items that need filing or organizing -->


## 💡 Ideas & Possibilities
<!-- Ideas, concepts, things to explore -->


## 🔄 Recurring / Rhythms
<!-- Regular commitments, habits, routines -->
`;
  clearedDumps.push({ fileKey: file.fileKey, domain: file.domain, content: clearedContent });
}

const hasContent = processedDomains.length > 0;

// Store for downstream nodes
const output = {
  hasContent,
  processedDomains,
  priorityATasks,
  priorityBTasks,
  reviewItems,
  clearedDumps,
  masterTaskListKey: MASTER_TASK_LIST_KEY,
  today
};

// Store in static data for cross-node access
$workflow.staticData.parseOutput = output;

return [{ json: output }];

// ═══════════════════════════════════════════════════════════
// BUILD ALL UPDATES
// Reads MTL binary, appends tasks, packages all files to write
// ═══════════════════════════════════════════════════════════

const parsed = $workflow.staticData.parseOutput;
const { priorityATasks, priorityBTasks, clearedDumps, masterTaskListKey, today } = parsed;

// Extract MTL content from binary
const binaryKey = Object.keys($input.item.binary || {})[0] || 'data';
const binaryData = $input.item.binary?.[binaryKey];
let mtlContent = binaryData?.data ? Buffer.from(binaryData.data, 'base64').toString('utf-8') : '';

// Section header map for Priority A (by area)
const PRI_A_HEADERS = {
  faith:      '### 🙏 Faith',
  family:     '### 💒 Marriage & Family',
  business:   '### 🚀 Business',
  consulting: '### 💼 Consulting',
  work:       '### 🏥 Work (Parallon)',
  health:     '### 💪 Health',
  home:       '### 🏠 Home',
  personal:   '### 🤖 Personal'
};

const PRI_B_HEADER = '## 🟡 Priority B';

function insertAfterHeader(content, header, newLines) {
  const idx = content.indexOf(header);
  if (idx === -1) {
    // Header not found — append at end
    return content.trimEnd() + '\n\n' + newLines.join('\n') + '\n';
  }
  const afterHeader = content.indexOf('\n', idx);
  const insertPoint = afterHeader !== -1 ? afterHeader + 1 : content.length;
  return content.slice(0, insertPoint) + newLines.join('\n') + '\n' + content.slice(insertPoint);
}

// Group Priority A tasks by area
const aTasksByArea = {};
for (const task of priorityATasks) {
  if (!aTasksByArea[task.area]) aTasksByArea[task.area] = [];
  aTasksByArea[task.area].push(task.line);
}

// Insert Priority A tasks under their area headers
for (const [area, lines] of Object.entries(aTasksByArea)) {
  const header = PRI_A_HEADERS[area];
  if (header) mtlContent = insertAfterHeader(mtlContent, header, lines);
}

// Insert Priority B tasks
if (priorityBTasks.length > 0) {
  const bLines = priorityBTasks.map(t => t.line);
  mtlContent = insertAfterHeader(mtlContent, PRI_B_HEADER, bLines);
}

// Build file write array: MTL first, then cleared brain dumps
const filesToWrite = [
  { fileKey: masterTaskListKey, content: mtlContent, label: 'Master Task List' },
  ...clearedDumps
];

return [{ json: { filesToWrite, count: filesToWrite.length } }];

// Convert string content to base64 binary for S3 upload
const item = $input.item.json;
const contentStr = item.content || '';
const base64 = Buffer.from(contentStr, 'utf-8').toString('base64');

return [{
  json: { fileKey: item.fileKey, label: item.label },
  binary: {
    data: {
      data: base64,
      mimeType: 'text/markdown',
      fileName: item.fileKey.split('/').pop() || 'file.md'
    }
  }
}];

// ═══════════════════════════════════════
// BUILD HTML DIGEST EMAIL
// ═══════════════════════════════════════
const d = $workflow.staticData.parseOutput;
const { processedDomains, priorityATasks, priorityBTasks, reviewItems, today } = d;

const totalReview = Object.values(reviewItems).reduce((s, a) => s + a.length, 0);

function taskCards(tasks, color) {
  if (!tasks.length) return '<p style="color:#888">None today.</p>';
  return tasks.map(t => `
    <div style="background:#1e1e2e;border-left:4px solid ${color};border-radius:8px;padding:12px 16px;margin:8px 0">
      <span style="font-size:1.1em">${t.emoji} ${t.raw}</span>
      ${t.rock ? `<span style="background:#f5a623;color:#000;font-size:0.75em;padding:2px 8px;border-radius:12px;margin-left:8px">${t.rock}</span>` : ''}
      ${t.due ? `<span style="color:#888;font-size:0.8em;margin-left:8px">📅 ${t.due}</span>` : ''}
    </div>`).join('');
}

function reviewSection(title, items) {
  if (!items.length) return '';
  return `<h3 style="color:#a0a0b0;margin:16px 0 8px">${title}</h3><ul style="color:#c8c8d8">${
    items.map(i => `<li><strong>${i.emoji || i.domain}:</strong> ${i.text}</li>`).join('')
  }</ul>`;
}

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"></head>
<body style="background:#13131f;color:#e0e0f0;font-family:system-ui,sans-serif;max-width:680px;margin:0 auto;padding:24px">
  <div style="background:linear-gradient(135deg,#667eea,#764ba2);border-radius:16px;padding:28px 32px;margin-bottom:24px">
    <h1 style="margin:0;color:#fff">🧠 Brain Dump Processed</h1>
    <p style="margin:8px 0 0;color:rgba(255,255,255,0.8)">${today} &bull; ${processedDomains.map(d=>d.emoji+' '+d.domain).join(' &bull; ')}</p>
  </div>
  <div style="display:flex;gap:12px;margin-bottom:24px">
    <div style="flex:1;background:#1e1e2e;border-radius:12px;padding:16px;text-align:center">
      <div style="font-size:2em;font-weight:700;color:#ff6b6b">${priorityATasks.length}</div>
      <div style="color:#888">Priority A</div>
    </div>
    <div style="flex:1;background:#1e1e2e;border-radius:12px;padding:16px;text-align:center">
      <div style="font-size:2em;font-weight:700;color:#f5a623">${priorityBTasks.length}</div>
      <div style="color:#888">Priority B</div>
    </div>
    <div style="flex:1;background:#1e1e2e;border-radius:12px;padding:16px;text-align:center">
      <div style="font-size:2em;font-weight:700;color:#4ecdc4">${totalReview}</div>
      <div style="color:#888">For Review</div>
    </div>
  </div>
  <h2 style="color:#ff6b6b">🔴 Priority A — Filed to Master List</h2>
  ${taskCards(priorityATasks, '#ff6b6b')}
  <h2 style="color:#f5a623">🟡 Priority B — Filed to Master List</h2>
  ${taskCards(priorityBTasks, '#f5a623')}
  ${reviewSection('📝 Notes (Review Only)', reviewItems.notes)}
  ${reviewSection('📚 Articles & Resources (Review Only)', reviewItems.articles)}
  ${reviewSection('💡 Ideas (Review Only)', reviewItems.ideas)}
  ${reviewSection('🗂️ To Organize (Review Only)', reviewItems.organize)}
  ${reviewSection('🔄 Recurring / Rhythms (Review Only)', reviewItems.recurring)}
  <hr style="border:1px solid #2a2a3e;margin:24px 0">
  <p style="color:#555;font-size:0.85em">Brain dumps cleared and ready for tomorrow &bull; Processed at ${new Date().toLocaleTimeString('en-US', {timeZone:'America/Chicago'})}</p>
</body></html>`;

return [{
  json: {
    subject: `🧠 Brain Dump Processed — ${priorityATasks.length + priorityBTasks.length} new tasks · ${today}`,
    html
  }
}];
